#include<bits/stdc++.h>
using namespace std;

int main()
{
    int n;
    scanf("%d",&n);
    long long ans=(n!=1);
    for(int i=1;i<n;i++)
    {
        long long sum=i,tmp=i;
        for(int j=2;j*j<=tmp;j++)
        {
            if(tmp%j==0)
            {
                sum=sum/j*(j-1);
                while(tmp%j==0)
                {
                    tmp/=j;
                }
            }
        }
        if(tmp>1)
        {
            sum=sum/tmp*(tmp-1);
        }
        ans+=sum*2;
    }
    printf("%lld",ans);
    return 0;
}
